package com.doc.entity.vendor;

import jakarta.persistence.*;
import lombok.*;

import java.util.Date;

/**
 * VendorOnboarding represents onboarding process after vendor is finalized/awarded.
 *
 * Flow:
 * RFQVendorAward
 *      ↓
 * Vendor Registration Form + Agreement Sent
 *      ↓
 * Vendor Uploads Documents
 *      ↓
 * Procurement Verification
 *      ↓
 * Legal Review
 *      ↓
 * Accounts Verification
 *      ↓
 * Vendor Activation
 *
 * Example:
 * Balaji Compliance Services selected for FSSAI Filing Support.
 * Now Balaji has to submit PAN, GST, bank details, signed agreement, NDA etc.
 */
@Entity
@Table(
        name = "vendor_onboardings",
        indexes = {
                @Index(name = "idx_onboarding_vendor", columnList = "vendor_id"),
                @Index(name = "idx_onboarding_status", columnList = "status"),
                @Index(name = "idx_onboarding_rfq", columnList = "rfq_id")
        }
)
@Getter
@Setter
@NoArgsConstructor
@AllArgsConstructor
public class VendorOnboarding {

    /**
     * Primary key of vendor onboarding table.
     */
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    /**
     * Unique onboarding number generated by system.
     *
     * Example:
     * VOB-FSSAI-2026-0001
     * VOB-NBFC-2026-0002
     */
    @Column(nullable = false, unique = true, length = 100)
    private String onboardingNumber;

    /**
     * Vendor who is being onboarded.
     *
     * Example:
     * Balaji Compliance Services.
     */
    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "vendor_id", nullable = false)
    private Vendor vendor;

    /**
     * RFQ from which vendor was finalized.
     *
     * Example:
     * RFQ-FSSAI-EMP-001.
     */
    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "rfq_id")
    private RFQ rfq;

    /**
     * Award record because of which onboarding started.
     *
     * Example:
     * Balaji awarded for FSSAI Filing Support.
     */
    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "vendor_finalization_id")
    private VendorFinalization vendorFinalization;

    /**
     * Service category for which vendor is being onboarded.
     *
     * Example:
     * FSSAI, NBFC, CDSCO, EPR_EWASTE, BIS, BAR_LICENSE.
     */
    @Column(length = 100)
    private String serviceCategory;

    /**
     * Work/service for which vendor is onboarded.
     *
     * Example:
     * FSSAI Filing Support, NBFC Documentation, EPR Recycler Coordination.
     */
    @Column(length = 255)
    private String onboardedFor;

    /**
     * Date when registration/agreement documents were sent to vendor.
     */
    @Temporal(TemporalType.TIMESTAMP)
    private Date formSentDate;

    /**
     * Date when vendor submitted signed documents.
     */
    @Temporal(TemporalType.TIMESTAMP)
    private Date documentsReceivedDate;

    /**
     * Procurement verification details.
     */
    private Long procurementVerifiedBy;

    @Temporal(TemporalType.TIMESTAMP)
    private Date procurementVerifiedDate;

    @Column(length = 1000)
    private String procurementRemarks;

    /**
     * Legal review details.
     */
    private Long legalReviewedBy;

    @Temporal(TemporalType.TIMESTAMP)
    private Date legalReviewedDate;

    @Column(length = 1000)
    private String legalRemarks;

    /**
     * Accounts verification details.
     */
    private Long accountsVerifiedBy;

    @Temporal(TemporalType.TIMESTAMP)
    private Date accountsVerifiedDate;

    @Column(length = 1000)
    private String accountsRemarks;

    /**
     * Final activation date.
     */
    @Temporal(TemporalType.TIMESTAMP)
    private Date activationDate;

    /**
     * Current onboarding status.
     */
    @Enumerated(EnumType.STRING)
    @Column(nullable = false, length = 50)
    private VendorOnboardingStatus status = VendorOnboardingStatus.ONBOARDING_PENDING;

    /**
     * General remarks for onboarding.
     */
    @Column(length = 1000)
    private String remarks;

    /**
     * User ID who created onboarding record.
     */
    private Long createdBy;

    /**
     * User ID who last updated onboarding record.
     */
    private Long updatedBy;

    /**
     * Record creation date.
     */
    @Temporal(TemporalType.TIMESTAMP)
    private Date createdDate;

    /**
     * Last update date.
     */
    @Temporal(TemporalType.TIMESTAMP)
    private Date updatedDate;

    /**
     * Soft delete flag.
     */
    private boolean isDeleted = false;

    @PrePersist
    public void onCreate() {
        this.createdDate = new Date();
        this.updatedDate = new Date();

        if (this.formSentDate == null) {
            this.formSentDate = new Date();
        }
    }

    @PreUpdate
    public void onUpdate() {
        this.updatedDate = new Date();

        if (this.status == VendorOnboardingStatus.ACTIVE && this.activationDate == null) {
            this.activationDate = new Date();
        }
    }
}